# Shape utilities module - provides geometric shapes and comparison functions

@abstract
class Shape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float

    @static
    PI: float = 3.14159

    def __init__(self, r: float):
        self.radius = r

    @override
    def area(self) -> float:
        return Circle.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * Circle.PI * self.radius

def compare_shapes(s1: Shape, s2: Shape) -> str:
    """Compare two shapes by area, return which is larger."""
    a1: float = s1.area()
    a2: float = s2.area()
    if a1 > a2:
        return "first"
    elif a2 > a1:
        return "second"
    return "equal"
